public struct BankingDashboardView: View {
    @StateObject private var service = BankingService()
    @State private var selectedAccountID: String?
    @State private var transactionAmount: String = ""
    @State private var transactionMemo: String = ""
    @State private var transactionType: TransactionType = .deposit
    
    public init() {}
    
    public var body: some View {
        NavigationView {
            VStack(spacing: 16) {
                if let message = service.lastErrorMessage {
                    Text(message)
                        .foregroundColor(.red)
                        .font(.footnote)
                        .padding(.horizontal)
                }
                
                List {
                    Section(header: Text("Accounts")) {
                        ForEach(service.accounts) { account in
                            Button(action: {
                                selectedAccountID = account.id
                            }) {
                                AccountRowView(account: account)
                            }
                            .buttonStyle(.plain)
                        }
                    }
                    
                    if let account = selectedAccount {
                        Section(header: Text("Create Transaction")) {
                            Picker("Type", selection: $transactionType) {
                                ForEach(TransactionType.allCases, id: \.self) { type in
                                    Text(type.rawValue.capitalized).tag(type)
                                }
                            }
                            TextField("Amount", text: $transactionAmount)
                                .keyboardType(.decimalPad)
                            TextField("Memo", text: $transactionMemo)
                            
                            Button("Submit Transaction") {
                                submitTransaction(for: account.id)
                            }
                        }
                        
                        Section(header: Text("Recent Transactions")) {
                            ForEach(account.recentTransactions) { transaction in
                                TransactionRowView(transaction: transaction, currencyCode: account.currencyCode)
                            }
                        }
                    }
                }
                .listStyle(.insetGrouped)
            }
            .navigationTitle("Banking")
            .onAppear {
                bootstrapIfNeeded()
            }
        }
    }
    
    private var selectedAccount: Account? {
        guard let selectedAccountID else { return service.accounts.first }
        return service.accounts.first(where: { $0.id == selectedAccountID })
    }
    
    private func bootstrapIfNeeded() {
        if service.accounts.isEmpty {
            let demo = Account(id: "0001", displayName: "Primary Checking", balance: 1250.75, currencyCode: "USD")
            service.addAccount(demo)
            selectedAccountID = demo.id
        }
    }
    
    private func submitTransaction(for accountID: String) {
        guard let amount = Decimal(string: transactionAmount), amount > 0 else {
            service.lastErrorMessage = TransactionError.invalidAmount.localizedDescription
            return
        }
        
        let transaction = Transaction(
            type: transactionType,
            amount: amount,
            memo: transactionMemo.isEmpty ? nil : transactionMemo
        )
        service.processTransaction(transaction, for: accountID)
        transactionAmount = ""
        transactionMemo = ""
    }
}

